1	<script setup lang="ts">
2	import { ref, computed, onMounted } from 'vue'
3	import hljs from 'highlight.js'
4	import 'highlight.js/styles/github.css'
5	import { ElMessage } from 'element-plus'
6	import { DocumentCopy } from '@element-plus/icons-vue'
7	
8	const props = withDefaults(
9	  defineProps<{
10	    code: string
11	    language?: string
12	  }>(),
13	  {
14	    language: 'plaintext',
15	  },
16	)
17	
18	const codeRef = ref<HTMLElement | null>(null)
19	
20	const highlightedCode = computed(() => {
21	  if (props.language && hljs.getLanguage(props.language)) {
22	    try {
23	      return hljs.highlight(props.code, { language: props.language }).value
24	    } catch {
25	      return hljs.highlightAuto(props.code).value
26	    }
27	  }
28	  return hljs.highlightAuto(props.code).value
29	})
30	
31	const displayLanguage = computed(() => {
32	  return props.language || 'plaintext'
33	})
34	
35	async function copyCode() {
36	  try {
37	    await navigator.clipboard.writeText(props.code)
38	    ElMessage.success('已复制到剪贴板')
39	  } catch {
40	    ElMessage.error('复制失败')
41	  }
42	}
43	
44	onMounted(() => {
45	  // Already highlighted via computed property
46	})
47	</script>
48	
49	<template>
50	  <div class="code-block">
51	    <div class="code-header">
52	      <span class="code-language">{{ displayLanguage }}</span>
53	      <el-button
54	        :icon="DocumentCopy"
55	        text
56	        size="small"
57	        class="copy-btn"
58	        @click="copyCode"
59	      >
60	        复制
61	      </el-button>
62	    </div>
63	    <pre class="code-content"><code ref="codeRef" v-html="highlightedCode"></code></pre>
64	  </div>
65	</template>
66	
