78	  justify-content: space-between;
79	  padding: 6px 12px;
80	  background-color: #f6f8fa;
81	  border-bottom: 1px solid var(--border-lighter);
82	}
83	
84	.code-language {
85	  font-size: 12px;
86	  color: var(--text-secondary);
87	  text-transform: uppercase;
88	  font-weight: 500;
89	}
90	
